// Test stackalloc with Span<nint> and Span<nuint>
Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Span<nuint> unsignedSpan = stackalloc nuint[4];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 20);

Console.WriteLine($"Span<nint> length: {signedSpan.Length}");
Console.WriteLine($"  Values: {signedSpan[0]}, {signedSpan[1]}, {signedSpan[2]}, {signedSpan[3]}");
Console.WriteLine($"  nint size: {nint.Size} bytes");

Console.WriteLine($"Span<nuint> length: {unsignedSpan.Length}");
Console.WriteLine($"  Values: {unsignedSpan[0]}, {unsignedSpan[1]}, {unsignedSpan[2]}, {unsignedSpan[3]}");
Console.WriteLine($"  nuint size: {nuint.Size} bytes");

